    11→import type { DetectedGesture, SwipeState } from "@/types/gestures";
    12→
    13→const MODEL_URL =
    14→  "https://storage.googleapis.com/mediapipe-models/gesture_recognizer/gesture_recognizer/float16/1/gesture_recognizer.task";
    15→
    16→const WASM_URL =
    17→  "https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@latest/wasm";
    18→
    19→interface UseGestureRecognizerOptions {
    20→  videoRef: React.RefObject<HTMLVideoElement | null>;
    21→  isVideoReady: boolean;
    22→  onGesture: (gesture: DetectedGesture) => void;
    23→}
    24→
    25→export function useGestureRecognizer({
    26→  videoRef,
    27→  isVideoReady,
    28→  onGesture,
    29→}: UseGestureRecognizerOptions) {
    30→  const recognizerRef = useRef<GestureRecognizer | null>(null);
    31→  const swipeStateRef = useRef<SwipeState>(createSwipeState());
    32→  const rafRef = useRef<number>(0);
    33→  const lastVideoTimeRef = useRef<number>(-1);
    34→  const [isLoading, setIsLoading] = useState(true);
    35→  const [error, setError] = useState<string | null>(null);
    36→  const onGestureRef = useRef(onGesture);
    37→  onGestureRef.current = onGesture;
    38→
    39→  // Initialize MediaPipe GestureRecognizer
    40→  useEffect(() => {
    41→    let cancelled = false;
    42→
    43→    async function init() {
    44→      try {
    45→        const vision = await FilesetResolver.forVisionTasks(WASM_URL);
    46→        if (cancelled) return;
    47→
    48→        const recognizer = await GestureRecognizer.createFromOptions(vision, {
    49→          baseOptions: { modelAssetPath: MODEL_URL, delegate: "GPU" },
    50→          runningMode: "VIDEO",
    51→          numHands: 1,
    52→          minHandDetectionConfidence: 0.5,
    53→          minHandPresenceConfidence: 0.5,
    54→          minTrackingConfidence: 0.5,
    55→        });
    56→
    57→        if (cancelled) {
    58→          recognizer.close();
    59→          return;
    60→        }
    61→
    62→        recognizerRef.current = recognizer;
    63→        setIsLoading(false);
    64→      } catch (err) {
    65→        if (!cancelled) {
    66→          setError(
    67→            err instanceof Error ? err.message : "Failed to load gesture model"
    68→          );
    69→          setIsLoading(false);
    70→        }
    71→      }
    72→    }
    73→
    74→    init();
    75→
    76→    return () => {
    77→      cancelled = true;
    78→      recognizerRef.current?.close();
    79→      recognizerRef.current = null;
    80→    };
    81→  }, []);
    82→
    83→  // Run recognition loop
    84→  useEffect(() => {
    85→    if (!isVideoReady || isLoading || !recognizerRef.current) return;
    86→
    87→    function processFrame() {
    88→      const video = videoRef.current;
    89→      const recognizer = recognizerRef.current;
    90→
    91→      if (!video || !recognizer || video.readyState < 2) {
    92→        rafRef.current = requestAnimationFrame(processFrame);
    93→        return;
    94→      }
    95→
    96→      if (video.currentTime === lastVideoTimeRef.current) {
    97→        rafRef.current = requestAnimationFrame(processFrame);
    98→        return;
    99→      }
   100→      lastVideoTimeRef.current = video.currentTime;
   101→
   102→      const now = performance.now();
   103→      const result = recognizer.recognizeForVideo(video, now);
   104→
   105→      // Check built-in gestures (thumbs up/down)
   106→      if (result.gestures.length > 0 && result.gestures[0].length > 0) {
   107→        const topGesture = result.gestures[0][0];
   108→        const detected = classifyBuiltInGesture(
   109→          topGesture.categoryName,
   110→          topGesture.score,
   111→          now
   112→        );
   113→        if (detected) {
   114→          onGestureRef.current(detected);
   115→        }
   116→      }
   117→
   118→      // Check swipe via landmark tracking (wrist = landmark 0)
   119→      if (result.landmarks.length > 0 && result.landmarks[0].length > 0) {
   120→        const wrist = result.landmarks[0][0];
   121→        const swipe = detectSwipe(swipeStateRef.current, wrist.x, now);
   122→        if (swipe) {
   123→          onGestureRef.current(swipe);
   124→        }
   125→      }
   126→
   127→      rafRef.current = requestAnimationFrame(processFrame);
   128→    }
   129→
   130→    rafRef.current = requestAnimationFrame(processFrame);
   131→
   132→    return () => {
   133→      cancelAnimationFrame(rafRef.current);
   134→    };
   135→  }, [isVideoReady, isLoading, videoRef]);
   136→
   137→  return { isLoading, error };
   138→}
